double closestPair(std::vector<Point> const& points) {
    double min_dist = DBL_MAX;

    // Initialize MPI
    int world_size, my_rank;
    MPI_Comm_size(MPI_COMM_WORLD, &world_size);
    MPI_Comm_rank(MPI_COMM_WORLD, &my_rank);

    if (points.empty()) return 0.0; // Handle empty input case

    // Divide points among ranks using round-robin approach
    std::vector<Point> local_points(points.size() / world_size + (my_rank < points.size() % world_size));
    for (size_t i = my_rank; i < points.size(); i += world_size) {
        local_points[i - my_rank] = points[i];
    }

    // Compute distances between all pairs of points in the subset using OpenMP
    double local_min_dist = DBL_MAX;
    #pragma omp parallel for reduction(min:local_min_dist)
    for (size_t i = 0; i < local_points.size(); ++i) {
        for (size_t j = i + 1; j < local_points.size(); ++j) {
            double dist = distance(local_points[i], local_points[j]);
            if (dist < local_min_dist) local_min_dist = dist;
        }
    }

    // Gather all minimum distances to rank 0
    std::vector<double> min_dists(world_size, DBL_MAX);
    MPI_Gather(&local_min_dist, 1, MPI_DOUBLE, &min_dists[0], 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);

    if (my_rank == 0) {
        // Find the global minimum distance
        std::sort(min_dists.begin(), min_dists.end());
        min_dist = min_dists.front();
    }

    // Finalize MPI and return result on rank 0
    MPI_Finalize();
    return my_rank == 0 ? min_dist : -1.0;
}
